/**
 * Notification log model — records every notification delivery attempt.
 *
 * Used by NotificationHistoryService to track and query notification history.
 */

import type { NotificationChannel, NotificationType, NotificationPriority } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed' | 'suppressed' | 'pending';

export interface NotificationLogEntry {
  id: string;
  notificationId: string;
  recipient: string;
  userId?: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  status: DeliveryStatus;
  errorMessage?: string;
  priority: NotificationPriority;
  timestamp: Date;
  metadata?: Record<string, string>;
}

export interface NotificationHistoryQuery {
  userId?: string;
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  from?: Date;
  to?: Date;
}

/**
 * Notification history service — tracks all notification delivery attempts.
 *
 * Stores notification log entries in-memory and provides query capabilities
 * for filtering by user, type, channel, status, and date range.
 *
 * Integrated with NotificationService: every send() call logs an entry here.
 */

import type {
  NotificationLogEntry,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

/** Reset the log ID counter. Useful for testing. */
export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');
  private entries: NotificationLogEntry[] = [];

  /**
   * Record a notification delivery attempt.
   */
  record(entry: Omit<NotificationLogEntry, 'id'>): NotificationLogEntry {
    const logEntry: NotificationLogEntry = {
      id: generateLogId(),
      ...entry,
    };
    this.entries.push(logEntry);
    this.logger.info(
      `Logged notification ${logEntry.notificationId} [${logEntry.status}] to ${logEntry.recipient} via ${logEntry.channel}`,
    );
    return logEntry;
  }

  /**
   * Query notification history with optional filters.
   * All filters are ANDed together.
   */
  query(filter: NotificationHistoryQuery): NotificationLogEntry[] {
    return this.entries.filter((entry) => {
      if (filter.userId !== undefined && entry.userId !== filter.userId) return false;
      if (filter.recipient !== undefined && entry.recipient !== filter.recipient) return false;
      if (filter.type !== undefined && entry.type !== filter.type) return false;
      if (filter.channel !== undefined && entry.channel !== filter.channel) return false;
      if (filter.status !== undefined && entry.status !== filter.status) return false;
      if (filter.from !== undefined && entry.timestamp < filter.from) return false;
      if (filter.to !== undefined && entry.timestamp > filter.to) return false;
      return true;
    });
  }

  /**
   * Get all log entries for a specific user.
   */
  getByUserId(userId: string): NotificationLogEntry[] {
    return this.query({ userId });
  }

  /**
   * Get all log entries for a specific notification type.
   */
  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
    return this.query({ type });
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(from: Date, to: Date): NotificationLogEntry[] {
    return this.query({ from, to });
  }

  /**
   * Get all log entries.
   */
  getAll(): NotificationLogEntry[] {
    return [...this.entries];
  }

  /**
   * Get total count of log entries, optionally filtered by status.
   */
  count(status?: NotificationLogEntry['status']): number {
    if (status) {
      return this.entries.filter((e) => e.status === status).length;
    }
    return this.entries.length;
  }

  /**
   * Clear all log entries. Useful for testing.
   */
  clear(): void {
    this.entries = [];
  }
}

