import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { PreferencesService } from '../../src/services/preferences.service.js';
import type { NotificationAdapter, SendResult } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

/** Stub adapter that always succeeds. */
class SuccessAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  async send(_payload: NotificationPayload): Promise<SendResult> {
    return { success: true };
  }
}

/** Stub adapter that always fails. */
class FailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  async send(_payload: NotificationPayload): Promise<SendResult> {
    return { success: false, errorMessage: 'delivery failed' };
  }
}

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date('2025-06-01T10:00:00Z'),
      updatedAt: new Date('2025-06-01T10:00:00Z'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2025-06-01T10:00:00Z'),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date('2025-06-01T10:00:00Z'),
      updatedAt: new Date('2025-06-01T10:00:00Z'),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date('2025-06-01T10:00:00Z'),
    ...overrides,
  };
}

function makeUserCreatedEvent(): UserCreatedEvent {
  return {
    type: 'user:created',
    user: {
      id: 'user-2',
      name: 'Bob',
      email: 'bob@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date('2025-06-02T12:00:00Z'),
  };
}

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    historyService = new NotificationHistoryService();
    notificationService = new NotificationService(eventBus, undefined, historyService);
    notificationService.registerAdapter(new SuccessAdapter());
    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  describe('record()', () => {
    it('should record a notification log entry', () => {
      const entry = historyService.record({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        userId: 'user-1',
        channel: 'email',
        type: 'order:confirmation',
        subject: 'Order Confirmation',
        status: 'sent',
        priority: 'normal',
        timestamp: new Date('2025-06-01T10:00:00Z'),
      });

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.status).toBe('sent');
    });

    it('should generate sequential log IDs', () => {
      const e1 = historyService.record({
        notificationId: 'notif-0001',
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order:confirmation',
        subject: 'Test',
        status: 'sent',
        priority: 'normal',
        timestamp: new Date(),
      });
      const e2 = historyService.record({
        notificationId: 'notif-0002',
        recipient: 'bob@example.com',
        channel: 'email',
        type: 'user:welcome',
        subject: 'Test',
        status: 'sent',
        priority: 'normal',
        timestamp: new Date(),
      });

      expect(e1.id).toBe('nlog-0001');
      expect(e2.id).toBe('nlog-0002');
    });
  });

  describe('integration with NotificationService', () => {
    it('should log sent notifications automatically', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.type).toBe('order:confirmation');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.userId).toBe('user-1');
    });

    it('should log failed notifications', async () => {
      notificationService.registerAdapter(new FailAdapter());

      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('failed');
      expect(logs[0]?.errorMessage).toBe('Adapter delivery failed');
    });

    it('should log suppressed notifications when preferences block them', async () => {
      const prefs = new PreferencesService();
      prefs.updateEmailPreferences('user-1', { enabled: false });

      const svc = new NotificationService(eventBus, prefs, historyService);
      svc.registerAdapter(new SuccessAdapter());
      // Need a new eventBus since old one already has handlers from beforeEach
      const bus2 = new EventBus();
      const svc2 = new NotificationService(bus2, prefs, historyService);
      svc2.registerAdapter(new SuccessAdapter());

      await bus2.emit(makeOrderCreatedEvent());

      const logs = historyService.query({ status: 'suppressed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.userId).toBe('user-1');
      expect(logs[0]?.type).toBe('order:confirmation');
    });

    it('should log pending notifications when no adapter is registered', async () => {
      const bus = new EventBus();
      const svc = new NotificationService(bus, undefined, historyService);
      // No adapter registered

      await bus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.status).toBe('pending');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const logs = historyService.getAll();
      expect(logs).toHaveLength(2);
      expect(logs[0]?.type).toBe('order:confirmation');
      expect(logs[1]?.type).toBe('order:status-update');
    });
  });

  describe('query()', () => {
    beforeEach(async () => {
      // Create several log entries via events
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      // Use a separate bus for a different user
      const bus2 = new EventBus();
      const svc2 = new NotificationService(bus2, undefined, historyService);
      svc2.registerAdapter(new SuccessAdapter());
      await bus2.emit(makeUserCreatedEvent());
    });

    it('should filter by userId', () => {
      const results = historyService.getByUserId('user-1');
      expect(results).toHaveLength(2);
      results.forEach((r) => expect(r.userId).toBe('user-1'));
    });

    it('should filter by type', () => {
      const results = historyService.getByType('order:confirmation');
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order:confirmation');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'email' });
      expect(results).toHaveLength(3);
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'sent' });
      expect(results).toHaveLength(3);
    });

    it('should filter by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2025-06-01T09:00:00Z'),
        new Date('2025-06-01T11:00:00Z'),
      );
      // Only events with timestamps in range
      expect(results.length).toBeGreaterThanOrEqual(1);
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        userId: 'user-1',
        type: 'order:confirmation',
        status: 'sent',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });

    it('should return empty array when no matches', () => {
      const results = historyService.query({ userId: 'nonexistent' });
      expect(results).toHaveLength(0);
    });
  });

  describe('count()', () => {
    it('should return total count', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      expect(historyService.count()).toBe(2);
    });

    it('should return count by status', async () => {
      notificationService.registerAdapter(new FailAdapter());
      await eventBus.emit(makeOrderCreatedEvent());

      // Re-register success adapter for next event
      notificationService.registerAdapter(new SuccessAdapter());
      await eventBus.emit(makeStatusChangedEvent());

      expect(historyService.count('failed')).toBe(1);
      expect(historyService.count('sent')).toBe(1);
    });

    it('should return 0 for empty history', () => {
      expect(historyService.count()).toBe(0);
    });
  });

  describe('clear()', () => {
    it('should remove all entries', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      expect(historyService.count()).toBe(1);

      historyService.clear();
      expect(historyService.count()).toBe(0);
      expect(historyService.getAll()).toHaveLength(0);
    });
  });

  describe('getByDateRange()', () => {
    it('should include entries at boundary timestamps', () => {
      const ts = new Date('2025-07-15T12:00:00Z');
      historyService.record({
        notificationId: 'notif-0001',
        recipient: 'test@example.com',
        channel: 'email',
        type: 'user:welcome',
        subject: 'Welcome',
        status: 'sent',
        priority: 'normal',
        timestamp: ts,
      });

      const results = historyService.getByDateRange(ts, ts);
      expect(results).toHaveLength(1);
    });

    it('should exclude entries outside range', () => {
      historyService.record({
        notificationId: 'notif-0001',
        recipient: 'test@example.com',
        channel: 'email',
        type: 'user:welcome',
        subject: 'Welcome',
        status: 'sent',
        priority: 'normal',
        timestamp: new Date('2025-01-01T00:00:00Z'),
      });

      const results = historyService.getByDateRange(
        new Date('2025-06-01T00:00:00Z'),
        new Date('2025-06-30T23:59:59Z'),
      );
      expect(results).toHaveLength(0);
    });
  });
});

