  // so use a wide range that includes now
  const now = new Date();
  const from = new Date(now.getTime() - 60_000);
  const to = new Date(now.getTime() + 60_000);
  const results = historyService.getByDateRange(from, to);
  expect(results).toHaveLength(3);
});

